import{_ as o,o as t,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"90. Workload Allocation And Safe Staffing","description":"","frontmatter":{"title":"90. Workload Allocation And Safe Staffing","eba":"Allied Health Professionals 2021-2026","topics":["hours","staffing","workload"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.md","filePath":"ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.md"}'),a={name:"ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.md"};function i(s,e,l,p,d,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_90-workload-allocation-and-safe-staffing" tabindex="-1">90. Workload Allocation And Safe Staffing <a class="header-anchor" href="#_90-workload-allocation-and-safe-staffing" aria-label="Permalink to &quot;90. Workload Allocation And Safe Staffing&quot;">​</a></h1><p><strong>90.1</strong> Purpose</p><p><strong>(a)</strong> The Employer acknowledges the benefits to both the organisation and individual Employees gained through Employees having a balance between both their professional and family life.</p><p><strong>(b)</strong> The allocation of work must consider the Employee’s hours of work, health, safety and welfare.</p><p><strong>(c)</strong> The Employer is obliged by the OHS Act to provide a safe workplace. It is recognised that adequate staffing affects workload and is relevant to occupational health and safety in the workplace</p><p><strong>90.2</strong> Work will be allocated so that an Employee does not work routinely beyond their ordinary hours of work to complete their duties, and the allocation of work does not require:</p><p><strong>(a)</strong> working before or after rostered ordinary hours;</p><p><strong>(b)</strong> working through meal intervals or rest/tea breaks; or</p><p><strong>(c)</strong> undertaking work at home which is not part of an agreed work from home arrangement.</p><p><strong>90.3</strong> Safe Staffing The Employer will ensure that it is sufficiently staffed and resourced so as to enable each Employee to:</p><p><strong>(a)</strong> perform all aspects of their role/position during their ordinary hours;</p><p><strong>(b)</strong> take rest intervals and meal breaks provided by this Agreement; and</p><p><strong>(c)</strong> take leave provided for by this Agreement and the NES.</p><p><strong>90.4</strong> Allocation of work</p><p><strong>(a)</strong> The Employer will allocate work to each Employee so that they can perform all aspects of their position (including meeting any targets or key performance indicators (KPIs)) during their ordinary hours of work, including but not limited to:</p><p><strong>(i)</strong> clinical duties;</p><p><strong>(ii)</strong> administrative and clerical duties;</p><p><strong>(iii)</strong> managerial/supervisory duties;</p><p><strong>(iv)</strong> educational duties;</p><p><strong>(v)</strong> attending meetings;</p><p><strong>(vi)</strong> clinical supervision; and</p><p><strong>(vii)</strong> duties related to the supervision, training and/or teaching of students. In doing so, the Employer will have regard to the Employee’s skills, abilities, capacity, experience, and any appropriate clinical guidelines for the profession and/or specialisation of the Employee.</p><p><strong>(b)</strong> The reference to ‘all aspects of their position (including meeting any targets or key performance indicators (KPIs)) during their ordinary hours’ in subclause 90.3(a) excludes unpaid work such as (but not limited to):</p><p><strong>(i)</strong> working before or after rostered ordinary hours;</p><p><strong>(ii)</strong> working through meal intervals or rest/tea breaks; and</p><p><strong>(iii)</strong> undertaking work at home which is not part of an agreed work from home arrangement.</p><p><strong>(c)</strong> The Employee’s work allocation, including any targets or KPIs will be provided in writing.</p><p><strong>90.5</strong> Reasonable overtime</p><p><strong>(a)</strong> All work performed by an Employee will be paid, in accordance with the provisions of this Agreement, with any hours worked by the Employee in addition to their ordinary hours to be paid as overtime or taken as time in lieu in accordance with <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clause 52</a>.</p><p><strong>(b)</strong> The Employer will not require work to be undertaken beyond an Employee’s ordinary hours of work, except where the overtime is reasonable (see <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clause 52</a> (Overtime)).</p><p><strong>(c)</strong> Notwithstanding subclause 90.5(b), an Employee will not generally be required to regularly undertake work beyond their ordinary hours of work.</p><p><strong>(d)</strong> Nothing in this clause 90 stops an Employee from agreeing to work overtime.</p><p><strong>90.6</strong> Consultation, Review and Disputes</p><p><strong>(a)</strong> The Employer and the Employee will consult regularly on the Employee’s workload.</p><p><strong>(b)</strong> An Employee/s and/or the Union (or other representative) may request a workload review at any time in writing.</p><p><strong>(c)</strong> Where a review is requested in writing, the Employer will:</p><p><strong>(i)</strong> consult with the Employee/s and the Union (where the Union has requested the workload review or the Employee/s are being represented by the Union);</p><p><strong>(ii)</strong> as part of that consultation, discuss and review the written work allocation required by subclause 90.4(c), including whether it is accurate;</p><p><strong>(iii)</strong> set out in writing any duties and responsibilities not in the written work allocation required by subclause 90.4(c) and the estimated time necessary for the Employee to complete all their duties and responsibilities; and</p><p><strong>(iv)</strong> where it is identified that the Employee is unable to complete all their work during their ordinary hours, the Employer will in writing: A. amend the Employee’s work allocation (including the estimated time to complete the tasks), to ensure the Employee can perform all aspects of their position during their ordinary work hours; B. set out any other steps to address the workload issue; and C. set out the process used to monitor workload.</p><p><strong>(d)</strong> Staffing and Collective workload issues In the event that a staffing issue or a collective workload issue is raised by an Employee/s and/or representative (including the Union), the Employer will consult with affected Employee/s and the representative (including the Union) and take appropriate steps to address any issues. To inform the consultation the Employer will provide relevant information requested by an Employee/s and/or representative (including the Union) that will provide clarification of the workload or staffing issues.</p><p><strong>(e)</strong> If, following consultation under subclause 90.6(c) or (d), the workload or staffing issue is not resolved, any party may refer it to either:</p><p><strong>(i)</strong> the dispute resolution procedure in this Agreement (<a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a>); or</p><p><strong>(ii)</strong> the Independent Disputes Resolution Panel (<a href="/eba/ebas/allied-health/consultation-disputes/14A-independent-dispute-resolution-panel.html">clause 14A</a>)</p><p><strong>90.7</strong> Information – Workplace Implementation Committee The matters in this clause 90 are directly relevant to workload and the Employer will provide information to the Workplace Implementation Committee as required Saf e Ro ster ing and F atigu e by subclause 83.2.</p>',45)])])}const u=o(a,[["render",i]]);export{c as __pageData,u as default};
